INSERT INTO crisis_incidents (title, description, severity, status, category, location, affected_stakeholders, lead_responder) VALUES
('Chemical Spill at Plant B', 'A chemical storage tank ruptured releasing 500 gallons of industrial solvent into the surrounding area. Emergency containment measures have been activated.', 'critical', 'active', 'Environmental', 'Houston, TX - Plant B', 'Local residents, EPA, employees, media', 'Sarah Chen'),
('Data Breach - Customer Records', 'Unauthorized access detected to customer database containing approximately 50,000 records including names, emails, and encrypted payment info.', 'critical', 'active', 'Cybersecurity', 'Corporate HQ - Server Room 3', 'Customers, shareholders, regulators', 'James Wilson'),
('Product Recall - Model X500', 'Safety defect identified in Model X500 product line. Potential overheating issue in battery component affecting units manufactured between Jan-Mar 2026.', 'high', 'monitoring', 'Product Safety', 'National - All Distribution Centers', 'Consumers, retailers, supply chain partners', 'Maria Garcia'),
('Executive Misconduct Allegations', 'Media reports alleging financial misconduct by CFO. Board has initiated internal investigation. Stock price dropped 8% in pre-market trading.', 'high', 'active', 'Reputation', 'Corporate Headquarters', 'Shareholders, board members, employees, regulators', 'Robert Johnson'),
('Factory Fire - Warehouse District', 'Major fire broke out in warehouse facility destroying inventory worth $2M. No injuries reported. Fire department on scene.', 'high', 'monitoring', 'Operational', 'Newark, NJ - Warehouse 7', 'Employees, insurance, supply chain, customers', 'Sarah Chen'),
('Social Media Viral Complaint', 'Customer video showing product failure went viral with 2M+ views. Negative sentiment trending on Twitter and TikTok.', 'medium', 'active', 'Reputation', 'Online - Social Media Platforms', 'Customers, brand advocates, media', 'Emily Taylor'),
('Labor Strike Announcement', 'Union representing 3,000 workers announced plans for strike action starting next Monday over wage disputes.', 'high', 'active', 'Labor Relations', 'Detroit, MI - Manufacturing Plant', 'Employees, union, customers, suppliers', 'Michael Lee'),
('Supply Chain Disruption', 'Key supplier in Taiwan halted operations due to earthquake. Expected 6-8 week delay on critical components.', 'medium', 'monitoring', 'Supply Chain', 'Taiwan - Supplier Facilities', 'Production team, customers, investors', 'Lisa Wang'),
('Regulatory Investigation', 'FDA announced investigation into compliance practices at our pharmaceutical division. Preliminary inquiry stage.', 'high', 'active', 'Regulatory', 'Washington, DC - FDA Office', 'Regulators, patients, healthcare providers, investors', 'Daniel Kim'),
('Workplace Safety Incident', 'Employee injured in manufacturing line accident. OSHA notification required. Worker hospitalized with non-life-threatening injuries.', 'medium', 'resolved', 'Workplace Safety', 'Chicago, IL - Plant A', 'Employees, OSHA, union, families', 'Amanda White'),
('Misinformation Campaign', 'Coordinated disinformation campaign on social media spreading false claims about product ingredients. Bot activity detected.', 'medium', 'active', 'Reputation', 'Online - Multiple Platforms', 'Consumers, media, health organizations', 'Rachel Davis'),
('Natural Disaster Response', 'Hurricane approaching Gulf Coast facilities. Evacuation plans activated for 3 locations. Business continuity plans in effect.', 'critical', 'active', 'Natural Disaster', 'Gulf Coast - LA, MS, AL', 'Employees, communities, customers, government', 'Chris Anderson'),
('Merger Leak - Confidential', 'Details of pending acquisition leaked to financial press before official announcement. SEC implications being assessed.', 'high', 'monitoring', 'Financial', 'New York, NY', 'Shareholders, SEC, employees, target company', 'Kevin Thompson'),
('Customer Data Privacy Complaint', 'Class action lawsuit filed alleging improper data sharing practices with third-party advertisers.', 'medium', 'active', 'Legal', 'San Francisco, CA - Federal Court', 'Customers, legal team, regulators, advertisers', 'Jennifer Martinez'),
('Environmental Protest', 'Environmental activist group staging protests outside corporate headquarters. Media coverage increasing. 200+ protesters present.', 'low', 'monitoring', 'Reputation', 'Corporate Headquarters', 'Activists, media, employees, community', 'David Brown')
INSERT INTO media_monitoring (source, title, url, sentiment, reach, platform, summary, published_at) VALUES
('CNN', 'Breaking: Major Chemical Spill Reported at Industrial Plant', 'https://cnn.com/2026/03/chemical-spill', 'negative', 5000000, 'TV/Online', 'CNN reporting on the chemical spill at Plant B with aerial footage showing containment efforts. Environmental impact assessment pending.', '2026-03-17 14:30:00'),
('Reuters', 'Company Faces Data Breach Affecting 50K Customers', 'https://reuters.com/2026/03/data-breach', 'negative', 3000000, 'Wire Service', 'Reuters wire story detailing the scope of the data breach. Cybersecurity experts comment on response timeline.', '2026-03-17 16:00:00'),
('Wall Street Journal', 'Stock Tumbles on CFO Misconduct Reports', 'https://wsj.com/2026/03/cfo-misconduct', 'negative', 2500000, 'Print/Online', 'WSJ deep dive into the financial misconduct allegations. Analyst downgrades expected.', '2026-03-16 08:00:00'),
('TikTok Viral', '@consumer_advocate Product Failure Video', 'https://tiktok.com/@consumer_advocate/viral', 'negative', 2100000, 'Social Media', 'Viral video showing product malfunction. Comments section flooded with similar complaints. 50K+ shares.', '2026-03-15 19:00:00'),
('Bloomberg', 'Company Initiates Product Recall for X500 Line', 'https://bloomberg.com/2026/03/recall-x500', 'neutral', 1800000, 'Financial News', 'Bloomberg coverage of the product recall. Estimated cost impact of $15-20M discussed.', '2026-03-16 10:30:00'),
('Local NBC Affiliate', 'Warehouse Fire Destroys Millions in Inventory', 'https://nbclocal.com/2026/03/warehouse-fire', 'negative', 500000, 'Local TV', 'Local news coverage of the warehouse fire with on-scene reporting. Community concerns about air quality.', '2026-03-17 22:00:00'),
('Twitter/X Trending', '#BoycottCompany Trending Nationally', 'https://twitter.com/trending/boycott', 'negative', 8000000, 'Social Media', 'Hashtag trending with 100K+ tweets. Mix of genuine concerns and coordinated amplification detected.', '2026-03-17 12:00:00'),
('Forbes', 'Crisis Management: How Companies Should Respond to Data Breaches', 'https://forbes.com/2026/03/crisis-management', 'neutral', 1200000, 'Online Magazine', 'Forbes article referencing the data breach as a case study. Expert opinions on best practices.', '2026-03-17 09:00:00'),
('Associated Press', 'Union Workers Prepare for Strike Action', 'https://ap.com/2026/03/union-strike', 'neutral', 4000000, 'Wire Service', 'AP coverage of the upcoming labor strike with union leadership quotes and company response statement.', '2026-03-16 15:00:00'),
('CNBC', 'Supply Chain Disruption Could Impact Q2 Earnings', 'https://cnbc.com/2026/03/supply-chain', 'negative', 2000000, 'Financial TV', 'CNBC segment analyzing potential financial impact of Taiwan supplier shutdown on quarterly results.', '2026-03-15 11:00:00'),
('New York Times', 'FDA Launches Investigation into Pharma Division', 'https://nytimes.com/2026/03/fda-investigation', 'negative', 3500000, 'Print/Online', 'NYT investigative report revealing details of FDA inquiry. Former employees quoted anonymously.', '2026-03-14 07:00:00'),
('Reddit r/technology', 'Data Breach Discussion Thread - 10K+ Upvotes', 'https://reddit.com/r/technology/data-breach', 'negative', 800000, 'Social Media', 'Reddit discussion thread with technical analysis of the breach. Security researchers weighing in.', '2026-03-17 20:00:00'),
('Guardian', 'Environmental Groups Demand Action After Chemical Spill', 'https://theguardian.com/2026/03/chemical-spill-response', 'negative', 2800000, 'Print/Online', 'Guardian article featuring environmental group statements and demands for stricter regulations.', '2026-03-18 06:00:00'),
('Industry Trade Journal', 'Product Safety Standards Under Review Following Recall', 'https://industrytrade.com/2026/03/safety-review', 'neutral', 200000, 'Trade Publication', 'Industry journal examining broader implications of the recall for manufacturing standards.', '2026-03-16 14:00:00'),
('Instagram', 'Employee Advocacy Posts Gaining Traction', 'https://instagram.com/company/employee-stories', 'positive', 350000, 'Social Media', 'Employee-generated content showing safety measures and community support efforts gaining positive engagement.', '2026-03-17 10:00:00')
INSERT INTO stakeholders (name, organization, role, email, phone, priority, relationship, notes) VALUES
('Dr. Patricia Hernandez', 'EPA Region 6', 'Regional Administrator', 'p.hernandez@epa.gov', '+1-214-555-0101', 'primary', 'Regulatory', 'Key contact for environmental incidents in TX region. Responsive to direct outreach.'),
('Mark Sullivan', 'Sullivan & Partners Law', 'Lead Counsel', 'm.sullivan@sullivanlaw.com', '+1-212-555-0202', 'primary', 'Legal Counsel', 'External crisis legal advisor. 20+ years experience in corporate crisis management.'),
('Angela Foster', 'National Consumer Safety Board', 'Commissioner', 'a.foster@ncsb.gov', '+1-202-555-0303', 'primary', 'Regulatory', 'Commissioner overseeing product safety. Met at industry conference last quarter.'),
('Tom Richards', 'ABC News Network', 'Senior Correspondent', 't.richards@abcnews.com', '+1-310-555-0404', 'primary', 'Media', 'Covers corporate stories nationally. Fair but persistent. Prefers exclusive interviews.'),
('Linda Chang', 'Investor Relations Group', 'Managing Director', 'l.chang@irgroup.com', '+1-415-555-0505', 'primary', 'Investor Relations', 'Manages communications with top 20 institutional investors. Critical during stock-moving events.'),
('Robert Okafor', 'City Council - Houston', 'Council Member District 5', 'r.okafor@houstontx.gov', '+1-713-555-0606', 'secondary', 'Government', 'Local government representative for Plant B district. Has been supportive but demands transparency.'),
('Dr. Susan Park', 'State Health Department', 'Chief Medical Officer', 's.park@statehealth.gov', '+1-512-555-0707', 'secondary', 'Regulatory', 'Relevant for health impact assessments. Quick response team available.'),
('Marcus Webb', 'United Workers Union', 'President', 'm.webb@uwunion.org', '+1-313-555-0808', 'primary', 'Labor', 'Union president leading strike negotiations. Open to dialogue but firm on demands.'),
('Cynthia Morales', 'Green Earth Alliance', 'Executive Director', 'c.morales@greenearth.org', '+1-503-555-0909', 'secondary', 'Activist/NGO', 'Leads environmental advocacy campaigns. Can amplify or de-escalate public pressure.'),
('Jason Park', 'TechSecure Consulting', 'CISO Consultant', 'j.park@techsecure.com', '+1-650-555-1010', 'primary', 'Consultant', 'Cybersecurity incident response lead. Available 24/7 for breach support.'),
('Diana Rodriguez', 'Major Retail Chain', 'VP of Procurement', 'd.rodriguez@retailchain.com', '+1-479-555-1111', 'secondary', 'Customer/Partner', 'Largest retail partner. Concerned about product recall impact on shelf space.'),
('William Chen', 'Taiwan Semiconductor Co.', 'VP Operations', 'w.chen@taiwansemi.com', '+886-2-555-1212', 'primary', 'Supplier', 'Key contact at disrupted supplier. Working on alternative supply arrangements.'),
('Nancy O''Brien', 'Insurance Corp of America', 'Claims Director', 'n.obrien@insurancecorp.com', '+1-860-555-1313', 'secondary', 'Insurance', 'Handling claims for warehouse fire and potential liability claims.'),
('Professor Alan Wright', 'MIT Crisis Communications Lab', 'Director', 'a.wright@mit.edu', '+1-617-555-1414', 'tertiary', 'Academic Advisor', 'Academic advisor on crisis communication strategy. Available for expert commentary.'),
('Karen Mitchell', 'Community Action Network', 'Community Organizer', 'k.mitchell@communityaction.org', '+1-713-555-1515', 'secondary', 'Community', 'Local community leader near Plant B. Can help facilitate town hall meetings.')
INSERT INTO response_templates (name, category, template_text, variables, use_case, tone, last_used) VALUES
('Initial Crisis Acknowledgment', 'General', 'We are aware of {{incident_description}} and are taking immediate action. The safety and well-being of {{affected_parties}} is our top priority. We have activated our crisis response team and are working with {{authorities}} to address the situation. We will provide updates as more information becomes available.', 'incident_description, affected_parties, authorities', 'First public statement when crisis breaks', 'Empathetic, Authoritative', '2026-03-17 10:00:00'),
('Data Breach Notification', 'Cybersecurity', 'We are writing to inform you that on {{date}}, we discovered unauthorized access to {{system_affected}}. The potentially affected data includes {{data_types}}. We immediately {{actions_taken}} and have engaged {{security_firm}} to conduct a thorough investigation. We are offering {{remediation}} to all affected individuals.', 'date, system_affected, data_types, actions_taken, security_firm, remediation', 'Notifying affected individuals of data breach', 'Transparent, Reassuring', '2026-03-17 16:30:00'),
('Product Recall Statement', 'Product Safety', 'We are voluntarily recalling {{product_name}} due to {{issue_description}}. This affects {{units_affected}} units manufactured between {{date_range}}. Consumers should {{consumer_action}}. We sincerely apologize for any inconvenience and are committed to {{resolution}}.', 'product_name, issue_description, units_affected, date_range, consumer_action, resolution', 'Public announcement of product recall', 'Concerned, Action-oriented', '2026-03-16 11:00:00'),
('Environmental Incident Response', 'Environmental', 'We are responding to {{incident_type}} at our {{location}} facility. Our emergency response team has implemented {{containment_measures}}. We are working closely with {{regulatory_bodies}} and environmental experts to {{remediation_plan}}. The health and safety of our community is paramount.', 'incident_type, location, containment_measures, regulatory_bodies, remediation_plan', 'Environmental incident public statement', 'Responsible, Proactive', '2026-03-17 15:00:00'),
('Investor Communication', 'Financial', 'Dear Shareholders, We want to address {{issue}} directly. {{context}}. Our management team is {{actions}}. We remain committed to {{commitments}} and will provide a detailed update during {{next_communication}}. We appreciate your continued confidence.', 'issue, context, actions, commitments, next_communication', 'Communication to shareholders during crisis', 'Professional, Reassuring', '2026-03-16 09:00:00'),
('Employee Internal Memo', 'Internal', 'Team, As you may be aware, {{situation}}. I want to assure you that {{leadership_actions}}. Your role during this time is {{employee_guidance}}. Please direct all media inquiries to {{media_contact}}. We will hold a company-wide briefing on {{briefing_date}}.', 'situation, leadership_actions, employee_guidance, media_contact, briefing_date', 'Internal communication to employees', 'Supportive, Direct', '2026-03-17 08:00:00'),
('Social Media Quick Response', 'Social Media', 'We hear your concerns about {{issue}}. We take this seriously and are {{action}}. For the latest updates, visit {{link}}. If you need immediate assistance, please contact {{contact_info}}.', 'issue, action, link, contact_info', 'Quick social media response to public concerns', 'Empathetic, Concise', '2026-03-17 13:00:00'),
('Media Statement - No Comment', 'Media', 'Thank you for reaching out. We are aware of {{topic}} and are currently {{status}}. We are not in a position to comment further at this time but will issue a formal statement by {{timeline}}. All inquiries should be directed to {{spokesperson}}.', 'topic, status, timeline, spokesperson', 'Holding statement when full response not ready', 'Professional, Measured', '2026-03-16 12:00:00'),
('Community Outreach Letter', 'Community', 'Dear {{community_name}} Residents, We understand your concerns regarding {{issue}}. We want you to know that {{actions_taken}}. We are committed to {{commitments}}. We invite you to attend a community meeting on {{meeting_date}} at {{location}} to discuss this directly.', 'community_name, issue, actions_taken, commitments, meeting_date, location', 'Outreach to affected community members', 'Compassionate, Transparent', '2026-03-17 11:00:00'),
('Regulatory Response Letter', 'Regulatory', 'Dear {{regulator_name}}, In response to your inquiry dated {{date}} regarding {{subject}}, we provide the following information: {{response_details}}. We remain fully committed to compliance and have implemented {{corrective_actions}}. Please find enclosed {{attachments}}.', 'regulator_name, date, subject, response_details, corrective_actions, attachments', 'Formal response to regulatory inquiry', 'Formal, Cooperative', '2026-03-15 14:00:00'),
('Customer Apology', 'Customer Relations', 'Dear Valued Customer, We sincerely apologize for {{issue}}. We understand this has caused {{impact}} and we take full responsibility. To make this right, we are {{remedy}}. Your trust means everything to us and we are committed to {{improvement_plan}}.', 'issue, impact, remedy, improvement_plan', 'Apology to affected customers', 'Sincere, Accountable', '2026-03-16 16:00:00'),
('Labor Dispute Statement', 'Labor Relations', 'We value our {{workforce_description}} and respect their right to {{action}}. We remain committed to {{negotiation_stance}}. We have proposed {{proposal_summary}} and continue to engage in good-faith negotiations. Our goal is {{desired_outcome}}.', 'workforce_description, action, negotiation_stance, proposal_summary, desired_outcome', 'Public statement during labor disputes', 'Respectful, Firm', '2026-03-16 13:00:00'),
('Crisis Update Bulletin', 'General', 'UPDATE - {{timestamp}}: {{update_summary}}. Key developments: {{developments}}. Next steps: {{next_steps}}. For ongoing updates, monitor {{channels}}. Emergency contact: {{emergency_contact}}.', 'timestamp, update_summary, developments, next_steps, channels, emergency_contact', 'Ongoing crisis update bulletins', 'Factual, Clear', '2026-03-17 18:00:00'),
('Partnership/Supplier Notice', 'Supply Chain', 'Dear {{partner_name}}, We are writing to inform you of {{situation}} that may impact {{impact_area}}. We are taking the following steps: {{mitigation_steps}}. We anticipate {{timeline}} for resolution. Your dedicated contact for this matter is {{contact_person}}.', 'partner_name, situation, impact_area, mitigation_steps, timeline, contact_person', 'Notification to business partners/suppliers', 'Professional, Solution-oriented', '2026-03-15 10:00:00'),
('Post-Crisis Recovery Statement', 'General', 'Following {{crisis_description}}, we are pleased to share that {{resolution_summary}}. Key outcomes include: {{outcomes}}. We have implemented {{preventive_measures}} to prevent recurrence. We thank {{acknowledgments}} for their support throughout this period.', 'crisis_description, resolution_summary, outcomes, preventive_measures, acknowledgments', 'Statement after crisis has been resolved', 'Optimistic, Grateful', '2026-03-14 09:00:00')
INSERT INTO press_releases (title, content, crisis_id, status, target_audience, ai_generated) VALUES
('Immediate Response to Chemical Spill at Plant B Facility', 'FOR IMMEDIATE RELEASE\n\nHouston, TX - March 17, 2026\n\nWe are responding to a chemical spill at our Plant B facility in Houston, Texas. At approximately 2:00 PM CST, a storage tank containing industrial solvent experienced a structural failure. Our emergency response team was activated within minutes and containment measures are in place.\n\nKey Facts:\n- No injuries have been reported\n- Containment barriers have been deployed\n- EPA has been notified and is on-site\n- Air quality monitoring stations have been activated\n\nWe are working closely with local authorities and environmental agencies to minimize impact and ensure public safety. Residents within a 1-mile radius are being advised to shelter in place as a precautionary measure.\n\nFor updates, visit our website or call our emergency hotline at 1-800-555-SAFE.', 1, 'published', 'General Public, Media, Regulators', false),
('Notice of Data Security Incident', 'FOR IMMEDIATE RELEASE\n\nMarch 17, 2026\n\nWe are writing to inform stakeholders of a data security incident discovered on March 17, 2026. Our cybersecurity team detected unauthorized access to a customer database.\n\nWhat Happened: Unauthorized access was gained to a database containing customer records.\nWhat Information Was Involved: Names, email addresses, and encrypted payment information.\nWhat We Are Doing: We have engaged leading cybersecurity firm TechSecure to investigate. All affected systems have been secured.\nWhat You Can Do: We recommend monitoring your financial accounts and enrolling in the complimentary credit monitoring service we are providing.\n\nWe take the protection of personal information extremely seriously and sincerely apologize for any concern this may cause.', 2, 'approved', 'Customers, Regulators, Media', false),
('Voluntary Product Recall: Model X500 Series', 'FOR IMMEDIATE RELEASE\n\nMarch 16, 2026\n\nWe are voluntarily recalling all Model X500 units manufactured between January and March 2026 due to a potential battery overheating issue identified during routine quality testing.\n\nApproximately 25,000 units are affected. No injuries have been reported to date. Customers should immediately stop using the product and contact us for a full refund or replacement.\n\nFree returns can be arranged by calling 1-800-555-RECALL or visiting our website. We apologize for the inconvenience and are committed to the highest safety standards.', 3, 'published', 'Consumers, Retailers, Media', false),
('Board of Directors Statement on Executive Investigation', 'FOR IMMEDIATE RELEASE\n\nMarch 16, 2026\n\nThe Board of Directors announces that it has initiated an independent investigation into allegations of financial misconduct involving a senior executive. The Board takes these allegations extremely seriously.\n\nThe executive in question has been placed on administrative leave pending the outcome of the investigation. An independent committee of the Board, supported by external counsel, will oversee the investigation.\n\nThe Company remains in full compliance with all regulatory requirements and continues to operate normally under the leadership of the existing management team.', 4, 'published', 'Investors, Regulators, Employees, Media', false),
('Update on Warehouse Fire Incident - Newark Facility', 'FOR IMMEDIATE RELEASE\n\nMarch 17, 2026\n\nWe can confirm that a fire occurred at our Newark, NJ warehouse facility earlier today. The fire has been contained and no injuries were reported. All employees were safely evacuated.\n\nThe cause of the fire is under investigation. We are working with our insurance providers and are implementing contingency plans to minimize supply chain disruption. Affected customer orders will be fulfilled from alternative locations.', 5, 'review', 'Customers, Partners, Media', false),
('Addressing Customer Concerns on Social Media', 'MEDIA STATEMENT\n\nMarch 17, 2026\n\nWe are aware of a video circulating on social media regarding one of our products. We take all customer feedback seriously and have reached out directly to the customer involved.\n\nOur quality assurance team is reviewing the specific incident. The safety and satisfaction of our customers is our top priority. We encourage any customers with concerns to contact our support team directly.', 6, 'draft', 'Social Media Users, Customers', true),
('Statement on Labor Negotiations', 'FOR IMMEDIATE RELEASE\n\nMarch 16, 2026\n\nWe remain committed to productive negotiations with the United Workers Union. We value our employees and recognize their important contributions.\n\nWe have presented a comprehensive proposal that includes wage increases, enhanced benefits, and improved working conditions. We urge both parties to continue negotiations in good faith to reach a resolution that benefits all stakeholders.', 7, 'approved', 'Employees, Union, Media, Community', false),
('Supply Chain Update for Partners and Customers', 'PARTNER COMMUNICATION\n\nMarch 16, 2026\n\nDue to recent natural disaster events affecting our supplier in Taiwan, we anticipate some delays in specific product lines. We are actively implementing our business continuity plans.\n\nAlternative suppliers have been identified and production ramp-up is expected within 3-4 weeks. We will work individually with affected partners to manage expectations and minimize impact.', 8, 'review', 'Partners, Customers', false),
('Response to FDA Inquiry', 'MEDIA STATEMENT\n\nMarch 15, 2026\n\nWe acknowledge the FDA preliminary inquiry into our pharmaceutical division operations. We are fully cooperating with the FDA and are committed to the highest standards of compliance.\n\nPatient safety is our paramount concern. Our products continue to meet all safety and efficacy standards. We are confident in our compliance programs and look forward to a constructive dialogue with the FDA.', 9, 'published', 'Healthcare Providers, Patients, Regulators, Media', false),
('Workplace Safety Commitment Following Incident', 'FOR IMMEDIATE RELEASE\n\nMarch 16, 2026\n\nFollowing a workplace incident at our Chicago facility, we want to reaffirm our unwavering commitment to employee safety. The affected employee is receiving full medical care and is expected to make a complete recovery.\n\nWe have conducted an immediate safety review and implemented additional protective measures. OSHA has been notified and we are fully cooperating with their review. All operations have been temporarily paused for a comprehensive safety audit.', 10, 'published', 'Employees, OSHA, Community', false),
('Combating Misinformation About Our Products', 'MEDIA STATEMENT\n\nMarch 17, 2026\n\nWe are aware of false claims circulating on social media regarding our product ingredients. These claims are categorically untrue. Our products meet all regulatory requirements and undergo rigorous quality testing.\n\nWe are working with social media platforms to address the spread of this misinformation and have engaged independent laboratories to provide verified testing results, which will be published on our website.', 11, 'draft', 'Consumers, Media, Health Organizations', true),
('Hurricane Preparedness and Business Continuity Update', 'FOR IMMEDIATE RELEASE\n\nMarch 17, 2026\n\nAs Hurricane approaching Gulf Coast, we have activated comprehensive emergency plans for our facilities in Louisiana, Mississippi, and Alabama. Employee safety is our first priority.\n\nAll non-essential operations have been suspended. Employees have been advised to follow local evacuation orders. Our business continuity team is ensuring minimal disruption to customers and partners.', 12, 'published', 'Employees, Customers, Community, Government', false),
('Statement on Confidential Business Discussions', 'MEDIA STATEMENT\n\nMarch 16, 2026\n\nWe do not comment on market speculation or rumors regarding potential business transactions. As a matter of policy, we will make appropriate disclosures in accordance with regulatory requirements at the appropriate time.\n\nWe remain focused on executing our strategic plan and delivering value to our shareholders.', 13, 'approved', 'Investors, Media, Regulators', false),
('Response to Data Privacy Litigation', 'LEGAL NOTICE\n\nMarch 17, 2026\n\nWe are aware of the class action lawsuit filed regarding our data practices. We believe the allegations are without merit and intend to vigorously defend our position.\n\nWe maintain robust data privacy practices and comply with all applicable data protection regulations. We are committed to transparency in how we handle customer data.', 14, 'review', 'Customers, Legal Community, Regulators', false),
('Engaging with Community Stakeholders on Environmental Concerns', 'COMMUNITY NOTICE\n\nMarch 17, 2026\n\nWe welcome the opportunity to engage with community members and environmental groups regarding their concerns. We have invited representatives to participate in an open dialogue at our upcoming community forum.\n\nDate: March 22, 2026\nTime: 6:00 PM\nLocation: Community Center, 500 Main Street\n\nWe are committed to being a responsible corporate neighbor and value the perspectives of all stakeholders.', 15, 'draft', 'Community, Activists, Media', false)
INSERT INTO social_media_responses (platform, message, crisis_id, status, tone, character_count, ai_generated) VALUES
('Twitter/X', 'We are aware of the situation at our Plant B facility and are taking immediate action. Emergency response teams are on-site. No injuries reported. Updates: [link] #SafetyFirst', 1, 'posted', 'Urgent, Professional', 168, false),
('Twitter/X', 'We take data security seriously. We have detected and contained a security incident. If you are a customer, please check your email for important information. More details: [link]', 2, 'posted', 'Transparent, Reassuring', 179, false),
('Facebook', 'Important Safety Notice: We are voluntarily recalling Model X500 units manufactured Jan-Mar 2026. Your safety is our priority. For return information, visit [link] or call 1-800-555-RECALL. We sincerely apologize for any inconvenience.', 3, 'posted', 'Concerned, Helpful', 237, false),
('LinkedIn', 'Our Board of Directors has taken swift and decisive action regarding recent allegations. An independent investigation is underway. We remain committed to the highest standards of corporate governance and transparency. Full statement: [link]', 4, 'posted', 'Professional, Authoritative', 243, false),
('Instagram', 'We want to address the video that has been shared about our product. We have reached out to the customer directly and our quality team is investigating. Your satisfaction matters to us. DM us if you have any concerns. #CustomerFirst', 6, 'posted', 'Empathetic, Responsive', 236, true),
('Twitter/X', 'Update on the Newark warehouse fire: All employees safe, fire contained. We are working to minimize any impact on deliveries. Thank you for your patience and understanding.', 5, 'posted', 'Calm, Informative', 171, false),
('Twitter/X', 'We value our dedicated workforce and remain at the negotiating table. We are committed to reaching a fair agreement that recognizes our employees contributions. #FairNegotiations', 7, 'scheduled', 'Respectful, Constructive', 180, false),
('Facebook', 'Due to a natural disaster affecting one of our key suppliers, some products may experience temporary delays. We are working hard to minimize disruption and will keep you updated. Thank you for your understanding.', 8, 'posted', 'Honest, Appreciative', 213, false),
('Twitter/X', 'We are fully cooperating with the FDA inquiry and are confident in our compliance practices. Patient safety remains our top priority. Statement: [link]', 9, 'posted', 'Professional, Confident', 149, false),
('TikTok', 'Safety is not just a policy - it is our culture. Following a recent incident, we have doubled down on safety training and protocols. Heres what we are doing to keep our team safe. [video link]', 10, 'draft', 'Authentic, Committed', 192, true),
('Twitter/X', 'False claims about our products are circulating online. Let us be clear: our products meet ALL regulatory standards. We are publishing independent lab results at [link]. Do not spread misinformation. #FactsFirst', 11, 'posted', 'Firm, Factual', 196, false),
('Facebook', 'Hurricane Update: The safety of our employees and communities comes first. We have activated emergency plans and are supporting local relief efforts. Stay safe. For employee resources: [link]', 12, 'posted', 'Caring, Urgent', 192, false),
('LinkedIn', 'We do not comment on market speculation. Our focus remains on delivering value through innovation and operational excellence. Stay tuned for our upcoming quarterly update.', 13, 'scheduled', 'Professional, Measured', 169, false),
('Twitter/X', 'We are committed to protecting your data privacy. We stand behind our data practices and will address the recent filing through proper legal channels. Your trust is paramount. [link]', 14, 'draft', 'Reassuring, Confident', 181, true),
('Instagram', 'We hear you, and we want to talk. Join us at our community forum on March 22 to discuss your environmental concerns face-to-face. Details in bio. Everyone is welcome. #CommunityFirst #OpenDialogue', 15, 'scheduled', 'Welcoming, Open', 199, false)
INSERT INTO sentiment_analyses (text_input, sentiment_score, sentiment_label, key_phrases, emotions, source, ai_analysis) VALUES
('The chemical spill is an absolute disaster. How could they let this happen? The whole neighborhood could be affected!', -0.850, 'Very Negative', 'chemical spill, disaster, neighborhood affected', 'anger, fear, frustration', 'Twitter/X', 'Strong negative sentiment driven by fear of environmental and health impacts. High emotional intensity suggests potential for viral spread. Recommended response: immediate transparent communication with specific safety measures.'),
('Just got the data breach notification email. At least they are offering credit monitoring. Could be worse I guess.', -0.300, 'Slightly Negative', 'data breach, notification, credit monitoring', 'concern, resignation, mild approval', 'Reddit', 'Mixed sentiment with slight negative lean. Customer acknowledges company response efforts. The resigned tone suggests this could be converted to neutral with strong follow-up communication.'),
('Really impressed with how quickly they initiated the product recall. Shows they care about safety over profits.', 0.750, 'Positive', 'impressed, quick recall, safety over profits', 'approval, trust, respect', 'Facebook', 'Positive sentiment recognizing swift corporate action. This type of response can be amplified as a case study in effective crisis response. Customer trust is being maintained.'),
('Another day another corporate scandal. These executives think they can get away with anything.', -0.700, 'Negative', 'corporate scandal, executives, get away', 'cynicism, anger, distrust', 'Twitter/X', 'Negative sentiment reflecting broader anti-corporate sentiment rather than specific incident knowledge. Generic distrust pattern. Difficult to address individually but demonstrates need for strong governance messaging.'),
('The warehouse fire is concerning but glad no one was hurt. Hope they have good insurance.', -0.150, 'Neutral', 'warehouse fire, no one hurt, insurance', 'concern, relief', 'Local News Comments', 'Near-neutral sentiment with slight concern. Relief about safety outcomes is a positive signal. The insurance comment suggests pragmatic assessment rather than emotional response.'),
('This viral video is crazy! Their product literally exploded. Never buying from them again.', -0.900, 'Very Negative', 'viral video, exploded, never buying again', 'shock, anger, distrust', 'TikTok Comments', 'Extremely negative sentiment with strong purchase intent impact. The word literally suggests exaggeration. Need fact-based response showing actual product performance and safety testing results.'),
('As a union member I support the strike. We deserve better wages and conditions.', -0.400, 'Negative', 'union, strike, better wages, conditions', 'solidarity, determination, frustration', 'Twitter/X', 'Moderately negative toward company from labor perspective. Organized sentiment likely to be amplified by union communications. Negotiation-focused messaging recommended.'),
('Supply chain issues are going to hurt this stock. Selling my position.', -0.600, 'Negative', 'supply chain, hurt stock, selling', 'worry, urgency, loss aversion', 'StockTwits', 'Financial-focused negative sentiment with actionable intent (selling stock). Indicates investor confidence erosion. Need clear timeline and alternative supply communication for investor audience.'),
('The FDA investigation is routine. People are overreacting. The company has always been compliant.', 0.300, 'Slightly Positive', 'FDA, routine, overreacting, compliant', 'confidence, dismissiveness', 'LinkedIn', 'Positive sentiment from likely insider or informed stakeholder. Useful perspective to amplify in communications. Shows that balanced voices exist in the conversation.'),
('Shout out to the safety team for evacuating everyone during the factory incident. Real heroes.', 0.850, 'Very Positive', 'safety team, evacuating, heroes', 'gratitude, admiration, pride', 'Facebook', 'Highly positive sentiment focused on employee safety response. Excellent candidate for amplification. Humanizes the company response and highlights preparedness.'),
('The misinformation about their products is clearly a coordinated attack. I have used their products for years with no issues.', 0.500, 'Positive', 'misinformation, coordinated attack, no issues, years', 'loyalty, skepticism toward claims', 'Twitter/X', 'Positive brand advocacy sentiment. Customer identifying misinformation pattern aligns with company messaging. Consider engaging this user as a brand advocate.'),
('Praying for everyone in the path of the hurricane. Hope the company takes care of their workers.', 0.200, 'Slightly Positive', 'praying, hurricane, take care, workers', 'empathy, hope, concern', 'Facebook', 'Empathetic sentiment with positive expectations of company behavior. Community-oriented. Company response should match these caring expectations with concrete employee support actions.'),
('If the merger rumors are true this stock is going to moon. Loading up shares now.', 0.700, 'Positive', 'merger, stock, loading up shares', 'excitement, greed, optimism', 'Reddit/WallStreetBets', 'Speculative positive sentiment driven by merger rumors. Not based on fundamentals. Company should not engage with speculation but ensure regulatory compliance in communications.'),
('Just joined the class action lawsuit. Its time these companies respect our privacy.', -0.750, 'Negative', 'class action, privacy, respect', 'anger, determination, righteous indignation', 'Twitter/X', 'Strong negative sentiment with legal action intent. Represents organized opposition. Legal team should monitor this conversation thread. Do not engage directly due to litigation.'),
('Went to the community meeting. The company reps were actually very open and answered tough questions. Cautiously optimistic.', 0.600, 'Positive', 'community meeting, open, tough questions, cautiously optimistic', 'cautious approval, hope, engagement', 'Neighborhood Forum', 'Positive outcome from community engagement effort. Face-to-face communication proving effective. Validates community outreach strategy. Continue building on this momentum.')
INSERT INTO crisis_simulations (scenario_name, description, severity, objectives, participants, status, results, lessons_learned, scheduled_date) VALUES
('Cyber Attack Tabletop Exercise', 'Simulated ransomware attack on critical infrastructure systems including customer databases and operational technology.', 'critical', 'Test incident response plan, validate communication chains, assess recovery time objectives', 'IT Security Team, Executive Leadership, Legal, PR, Operations', 'completed', 'Response time: 45 min to detection, 2 hours to containment. Communication chain had 15-min gap between IT and Executive notification.', 'Need dedicated crisis communication channel. IT-to-leadership notification must be automated. Backup communication plan needed for system outages.', '2026-02-15 09:00:00'),
('Product Contamination Scenario', 'Simulated discovery of contaminated product on store shelves with potential health risks to consumers.', 'critical', 'Test recall procedures, validate stakeholder notification process, assess media response readiness', 'Quality Assurance, Supply Chain, Legal, PR, Customer Service', 'completed', 'Recall notification sent within 4 hours. Media statement ready within 2 hours. Retailer notification process identified as bottleneck.', 'Retailer contact database needs updating. Pre-drafted recall templates saved significant time. Customer service team needs additional training on recall scripts.', '2026-02-20 10:00:00'),
('Executive Crisis Drill', 'Scenario involving sudden CEO health emergency during major product launch event with live media coverage.', 'high', 'Test succession communication plan, validate spokesperson readiness, assess market impact response', 'Board Members, C-Suite, Investor Relations, PR, Legal', 'completed', 'Backup spokesperson identified and briefed within 30 minutes. Market communication drafted in 45 minutes. Board notification completed in 20 minutes.', 'Need more trained spokespersons. Pre-prepared holding statements essential. Investor relations team performed exceptionally well.', '2026-01-25 14:00:00'),
('Natural Disaster Response Drill', 'Simulated Category 4 hurricane impacting multiple operational facilities simultaneously with employee safety concerns.', 'critical', 'Test evacuation procedures, validate business continuity plan, assess employee communication effectiveness', 'Facilities Management, HR, Operations, Safety, IT', 'completed', 'Employee accounting completed in 3 hours for 5,000+ staff. Three facilities successfully transitioned to backup operations. Two communication gaps identified in remote locations.', 'Satellite communication backup critical for disaster scenarios. Employee emergency contact database 85% current - needs improvement. Remote work capabilities tested successfully.', '2026-03-01 08:00:00'),
('Social Media Crisis Simulation', 'Viral negative content scenario with coordinated bot amplification and mainstream media pickup.', 'medium', 'Test social media monitoring response time, validate escalation procedures, assess content approval workflow', 'Social Media Team, PR, Legal, Marketing, Customer Service', 'completed', 'First response within 15 minutes of detection. Escalation to management in 25 minutes. Legal review created 1-hour bottleneck for official response.', 'Need pre-approved response templates for common scenarios. Legal team should have dedicated crisis reviewer available. Social media team performed well under pressure.', '2026-02-10 13:00:00'),
('Supply Chain Disruption Exercise', 'Simulated simultaneous failure of two major suppliers with 60-day recovery timeline.', 'high', 'Test alternative supplier activation, validate inventory buffer adequacy, assess customer communication plan', 'Procurement, Operations, Sales, Customer Service, Finance', 'completed', 'Alternative suppliers identified within 24 hours (simulated). Inventory buffer sufficient for 3 weeks. Customer communication template effective but lacked personalization.', 'Maintain relationships with 3+ alternative suppliers per critical component. Inventory buffer should cover 6 weeks minimum. Customer communication should segment by impact level.', '2026-02-05 10:00:00'),
('Regulatory Raid Scenario', 'Simulated unannounced regulatory inspection with document requests and employee interviews.', 'high', 'Test document preservation procedures, validate employee guidance protocols, assess legal response readiness', 'Legal, Compliance, HR, Operations, Executive Leadership', 'completed', 'Legal team on-site within 45 minutes. Document hold implemented in 1 hour. Employee guidance distributed in 2 hours. Two compliance gaps identified.', 'All employees need annual training on regulatory interaction protocols. Document retention policies need quarterly review. Legal should have ready-bag with key documents.', '2026-01-15 11:00:00'),
('Workplace Violence Response', 'Simulated active threat scenario at corporate headquarters during business hours.', 'critical', 'Test lockdown procedures, validate law enforcement coordination, assess employee safety communication', 'Security, HR, Facilities, Executive Leadership, External Law Enforcement', 'completed', 'Lockdown initiated in 3 minutes. Law enforcement notified in 2 minutes. All-clear communication took 45 minutes - too slow. Employee accountability achieved in 2 hours.', 'Panic button system needs upgrade. Communication during lockdown relies too heavily on email - need SMS/app alerts. Regular lockdown drills critical. Counseling resources should be pre-arranged.', '2026-01-20 15:00:00'),
('Multi-site Environmental Incident', 'Simulated simultaneous environmental incidents at three different facilities requiring coordinated response.', 'critical', 'Test multi-site coordination, validate environmental response capacity, assess regulatory notification compliance', 'Environmental Health & Safety, Operations, Legal, PR, Government Affairs', 'planned', NULL, NULL, '2026-04-01 09:00:00'),
('Hostile Takeover Communication Drill', 'Simulated hostile acquisition attempt requiring rapid stakeholder communication and defense strategy.', 'high', 'Test poison pill communication, validate board notification speed, assess shareholder communication readiness', 'Board, Legal, Investor Relations, PR, Executive Leadership', 'planned', NULL, NULL, '2026-04-15 10:00:00'),
('Pandemic Resurgence Plan Test', 'Testing business continuity plans for a new pandemic wave affecting 40% of workforce simultaneously.', 'high', 'Test remote work scalability, validate essential worker policies, assess communication effectiveness', 'HR, IT, Operations, Executive Leadership, Facilities', 'planned', NULL, NULL, '2026-05-01 09:00:00'),
('Data Center Failure Scenario', 'Simulated catastrophic failure of primary data center with cascading service outages.', 'critical', 'Test disaster recovery procedures, validate failover systems, assess customer communication during outage', 'IT, Operations, Customer Service, PR, Executive Leadership', 'in_progress', NULL, NULL, '2026-03-18 10:00:00'),
('Brand Ambassador Controversy', 'Scenario where a major brand ambassador makes controversial public statements requiring brand distancing.', 'medium', 'Test partnership termination procedures, validate social media response strategy, assess brand impact mitigation', 'Marketing, PR, Legal, Social Media, Executive Leadership', 'planned', NULL, NULL, '2026-04-20 14:00:00'),
('International Sanctions Compliance', 'Simulated discovery of inadvertent sanctions violation through third-party supplier network.', 'high', 'Test compliance notification procedures, validate supply chain audit capabilities, assess regulatory response', 'Legal, Compliance, Procurement, Government Affairs, Finance', 'planned', NULL, NULL, '2026-05-10 11:00:00'),
('Mass Layoff Communication Exercise', 'Testing communication strategy and execution for a significant workforce reduction affecting 500+ employees.', 'high', 'Test HR communication cascade, validate media strategy, assess employee support program readiness', 'HR, Legal, PR, Executive Leadership, IT, Facilities', 'planned', NULL, NULL, '2026-05-15 09:00:00')
