(10, 'Phone', 'Amanda White', 'OSHA Regional Office', 'Mandatory incident report filed. Provided details of workplace injury, root cause analysis, and corrective actions taken.', 'outbound', 'completed'),
(12, 'SMS Broadcast', 'Chris Anderson', 'All Gulf Coast Employees', 'URGENT: Hurricane evacuation order in effect. Report to designated assembly points. Check email for detailed instructions.', 'outbound', 'delivered'),
(1, 'Press Conference', 'Sarah Chen', 'Media Pool', 'Held press conference at Plant B providing update on containment progress, environmental monitoring results, and community support measures.', 'outbound', 'completed'),
(2, 'Hotline', 'Customer Service', 'Multiple Callers', 'Received 847 calls to data breach hotline in first 6 hours. Average wait time: 4 minutes. 92% resolution rate.', 'inbound', 'ongoing'),
(14, 'Legal Filing', 'Legal Department', 'Federal Court', 'Filed motion to dismiss class action complaint. Submitted evidence of compliance with data privacy regulations.', 'outbound', 'filed')
