INSERT INTO incident_timelines (crisis_id, event_title, event_description, event_type, timestamp, reported_by, impact_level) VALUES
(1, 'Tank Rupture Detected', 'Sensors detected pressure drop in Chemical Storage Tank 7. Automated alarm triggered.', 'detection', '2026-03-17 14:02:00', 'Automated Monitoring System', 'critical'),
(1, 'Emergency Response Activated', 'Plant B emergency response team deployed to containment area. Area evacuated within 8 minutes.', 'response', '2026-03-17 14:10:00', 'Plant Safety Manager', 'high'),
(1, 'EPA Notified', 'Formal notification sent to EPA Region 6 per regulatory requirements.', 'notification', '2026-03-17 14:25:00', 'Sarah Chen', 'medium'),
(1, 'Containment Barriers Deployed', 'Physical containment barriers fully deployed around spill perimeter. Estimated 500 gallons released.', 'response', '2026-03-17 14:45:00', 'Emergency Response Team', 'high'),
(1, 'Media Inquiries Begin', 'First media inquiries received from local Houston news stations.', 'media', '2026-03-17 15:00:00', 'PR Department', 'medium'),
(2, 'Anomalous Access Detected', 'Security monitoring tools flagged unusual database query patterns from an internal service account.', 'detection', '2026-03-17 09:30:00', 'Security Operations Center', 'critical'),
(2, 'Access Terminated', 'Compromised credentials revoked. Affected systems isolated from network.', 'response', '2026-03-17 10:15:00', 'IT Security Team', 'high'),
(2, 'Forensic Investigation Initiated', 'TechSecure engaged for forensic analysis. Evidence preservation procedures activated.', 'investigation', '2026-03-17 11:00:00', 'James Wilson', 'high'),
(2, 'Customer Notification Approved', 'Legal reviewed and approved customer breach notification template.', 'decision', '2026-03-17 15:00:00', 'Legal Department', 'medium'),
(3, 'Defect Identified in Testing', 'Routine quality testing revealed battery overheating in X500 units under specific conditions.', 'detection', '2026-03-14 11:00:00', 'Quality Assurance Lab', 'high'),
(3, 'Voluntary Recall Decision', 'Executive committee approved voluntary recall of all affected X500 units.', 'decision', '2026-03-15 16:00:00', 'CEO', 'critical'),
(3, 'CPSC Notification Filed', 'Consumer Product Safety Commission formally notified of voluntary recall.', 'notification', '2026-03-16 09:00:00', 'Maria Garcia', 'high'),
(7, 'Strike Notice Received', 'Formal 7-day strike notice received from United Workers Union leadership.', 'detection', '2026-03-10 08:00:00', 'HR Department', 'high'),
(12, 'Hurricane Watch Issued', 'National Weather Service issued hurricane watch for Gulf Coast including our facility locations.', 'detection', '2026-03-16 06:00:00', 'Chris Anderson', 'high'),
(12, 'Evacuation Order Activated', 'Company-wide evacuation order issued for all three Gulf Coast facilities.', 'response', '2026-03-17 08:00:00', 'Chris Anderson', 'critical')
INSERT INTO risk_assessments (title, description, category, likelihood, impact, risk_score, mitigation_strategy, status, ai_analysis) VALUES
('Repeat Chemical Spill Risk', 'Risk of additional chemical storage tank failures at aging Plant B facility. Infrastructure is 25+ years old.', 'Environmental', 4, 5, 20, 'Immediate: Install additional sensors and automated shutoff valves. Short-term: Conduct full structural assessment of all tanks. Long-term: Plan phased replacement of aging infrastructure.', 'analyzing', 'AI analysis indicates that facilities of similar age have a 3x higher incident rate. Predictive maintenance data suggests Tank 3 and Tank 12 are next highest risk. ROI on preventive replacement is positive within 2 years when factoring potential spill costs.'),
('Secondary Data Breach Attempt', 'Risk of follow-up attacks using intelligence gathered from initial breach. Threat actors may have mapped network topology.', 'Cybersecurity', 4, 5, 20, 'Deploy enhanced monitoring on all endpoints. Conduct full penetration test. Reset all service account credentials. Implement zero-trust architecture for sensitive databases.', 'analyzing', 'Pattern analysis of similar breaches shows 60% probability of follow-up attack within 90 days. Recommend immediate implementation of enhanced monitoring and credential rotation across all systems.'),
('Product Liability Litigation', 'Risk of personal injury lawsuits from X500 product defect. Even though no injuries reported, proactive legal preparation needed.', 'Legal', 3, 4, 12, 'Preserve all quality testing records. Engage product liability defense counsel. Document all recall communications and customer responses. Prepare for potential class action.', 'identified', 'Based on similar product recall cases, estimated litigation risk is moderate. Voluntary recall demonstrates good faith. Recommend proactive settlement fund allocation of $5-10M.'),
('Investor Confidence Erosion', 'Multiple concurrent crises risk compounding investor concern. Stock price already down 8% on CFO allegations alone.', 'Financial', 4, 4, 16, 'Schedule investor roadshow within 2 weeks. Prepare detailed Q&A document for analyst calls. Consider accelerating share buyback program. Release positive operational metrics.', 'analyzing', 'Market sentiment analysis shows correlation between crisis count and stock performance. Each additional crisis compounds negative impact by approximately 2-3%. Recommend consolidated positive narrative.'),
('Community Relations Deterioration', 'Plant B community trust at risk following chemical spill. Long-term relationship damage could affect operating permits and expansion plans.', 'Reputation', 3, 3, 9, 'Host community town halls. Establish community monitoring committee. Fund local environmental restoration project. Provide regular air and water quality reports to residents.', 'identified', 'Community sentiment mapping shows 65% negative perception in 5-mile radius. Historical data shows community trust recovery takes 12-18 months with active engagement program.'),
('Regulatory Fine Escalation', 'FDA investigation could expand beyond preliminary inquiry into formal enforcement action.', 'Regulatory', 3, 4, 12, 'Conduct internal compliance audit immediately. Engage former FDA officials as consultants. Prepare voluntary correction plan. Document all compliance improvements.', 'analyzing', 'FDA enforcement patterns suggest 40% of preliminary inquiries escalate to formal action. Voluntary corrective measures reduce escalation probability by approximately 50%.'),
('Supply Chain Single Point of Failure', 'Taiwan supplier disruption reveals over-reliance on single-source components for critical product lines.', 'Operational', 5, 4, 20, 'Qualify minimum 2 alternative suppliers for each critical component. Build strategic inventory buffer of 8 weeks. Develop regional diversification plan for supply base.', 'identified', 'Supply chain vulnerability analysis reveals 12 critical components with single-source dependency. Geographic concentration in earthquake-prone regions increases compound risk.'),
('Employee Morale Decline', 'Multiple crises creating anxiety and uncertainty among workforce. Retention risk increasing especially for key talent.', 'Human Resources', 4, 3, 12, 'Increase frequency of internal communications. Launch employee support program. Conduct pulse surveys. Ensure managers are equipped for difficult conversations. Consider retention bonuses for key roles.', 'identified', 'Employee sentiment data from internal channels shows 30% decline in engagement scores over past month. Exit interview data indicates crisis fatigue as emerging theme.'),
('Brand Reputation Damage', 'Cumulative impact of multiple simultaneous crises on brand equity. Consumer trust metrics declining.', 'Reputation', 4, 5, 20, 'Commission brand health study. Develop brand recovery campaign. Invest in positive storytelling through owned channels. Consider CSR initiative tied to crisis themes.', 'analyzing', 'Brand tracking data shows 15-point decline in Net Promoter Score over 30 days. Competitive analysis shows rival brands gaining consideration among our customer base.'),
('Labor Strike Operational Impact', 'Potential 3,000-worker strike could halt production for weeks. Customer commitments at risk.', 'Operational', 4, 4, 16, 'Prepare contingency workforce plan. Build finished goods inventory. Communicate potential delays to key customers proactively. Accelerate negotiation timeline.', 'identified', 'Strike duration modeling suggests 2-3 week average for similar disputes. Estimated revenue impact of $5M per week of production stoppage.'),
('Misinformation Campaign Escalation', 'Coordinated disinformation could expand to new platforms and topics. Bot network may be state-sponsored.', 'Reputation', 3, 3, 9, 'Engage digital forensics firm to trace bot network. Work with platform trust and safety teams. Prepare fact-check content library. Brief mainstream media on disinformation tactics.', 'analyzing', 'Bot network analysis reveals characteristics consistent with commercial disinformation services. Campaign shows signs of being funded rather than organic. Platform reporting may be most effective countermeasure.'),
('Hurricane Business Interruption', 'Extended facility closures could last 2-4 weeks post-hurricane. Revenue impact across three locations.', 'Natural Disaster', 5, 4, 20, 'Activate business continuity plans. Pre-position recovery equipment. Ensure adequate business interruption insurance coverage. Establish remote work capabilities for office staff.', 'mitigated', 'Historical hurricane recovery data for Gulf Coast industrial facilities shows average 18-day closure. Pre-positioned recovery resources can reduce this by 40%.'),
('Merger Information Leak Investigation', 'SEC investigation risk from premature disclosure of material non-public information about pending acquisition.', 'Legal/Regulatory', 3, 5, 15, 'Conduct internal investigation into leak source. Engage SEC counsel proactively. Review and strengthen information barrier procedures. Assess impact on deal timeline and terms.', 'analyzing', 'SEC enforcement data shows increased scrutiny of pre-announcement leaks. Proactive self-reporting typically results in more favorable outcomes. Recommend engagement with SEC within 48 hours.'),
('Class Action Scope Expansion', 'Risk of class action lawsuit expanding beyond initial data privacy claims to include additional causes of action.', 'Legal', 3, 4, 12, 'Engage top-tier litigation firm. Prepare comprehensive discovery response. Document all data practices and consent mechanisms. Consider early mediation to limit exposure.', 'identified', 'Similar class actions have expanded in 55% of cases. Average settlement range for comparable data privacy cases: $10-50M. Early mediation shows 30% cost reduction.'),
('Cumulative Crisis Fatigue', 'Organization managing 15 simultaneous crises. Risk of errors increasing due to team burnout and resource strain.', 'Organizational', 5, 4, 20, 'Prioritize crises by severity and impact. Bring in external crisis support resources. Implement shift rotations for crisis team. Ensure leadership is modeling self-care.', 'identified', 'Organizational stress indicators at highest levels recorded. Crisis management literature shows error rates increase 300% when teams manage more than 5 simultaneous incidents. Immediate resource augmentation recommended.')
INSERT INTO talking_points (crisis_id, topic, points, target_audience, tone, spokesperson, ai_generated, status) VALUES
(1, 'Chemical Spill - Community Safety', '1. Safety is our absolute top priority - we activated emergency protocols within minutes.\n2. No injuries have been reported and containment is in place.\n3. We are working hand-in-hand with the EPA and local authorities.\n4. Air and water quality monitoring stations are active and readings are within safe levels.\n5. We will host a community town hall within 48 hours to answer all questions directly.', 'Community Residents', 'Empathetic, Reassuring', 'Sarah Chen', false, 'approved'),
(2, 'Data Breach - Customer Communication', '1. We discovered the breach through our own monitoring and immediately took action.\n2. Affected data is limited to names, emails, and encrypted payment info - no plaintext financial data was exposed.\n3. We have engaged leading cybersecurity experts for a thorough investigation.\n4. Free credit monitoring and identity protection services are available to all affected customers.\n5. We have implemented additional security measures to prevent future incidents.', 'Customers', 'Transparent, Accountable', 'James Wilson', false, 'approved'),
(2, 'Data Breach - Media Talking Points', '1. We take data security extremely seriously and invested $X million in cybersecurity last year.\n2. We detected the breach through proactive monitoring and responded within hours.\n3. We are fully cooperating with law enforcement.\n4. We are going beyond legal requirements in our notification and remediation efforts.\n5. If asked about specifics of the attack, defer to ongoing investigation.', 'Media', 'Professional, Transparent', 'James Wilson', false, 'approved'),
(3, 'Product Recall - Consumer Safety', '1. We discovered this issue through our own quality testing before any injuries occurred.\n2. We made the decision to recall immediately - customer safety comes before profits.\n3. Full refund or replacement available to all affected customers.\n4. The recall process is simple - call our hotline or visit our website.\n5. We are implementing enhanced quality testing to prevent similar issues.', 'Consumers', 'Caring, Action-oriented', 'Maria Garcia', false, 'approved'),
(4, 'Executive Investigation - Investor Talking Points', '1. The Board took immediate action upon learning of the allegations.\n2. An independent investigation is being conducted by external counsel.\n3. The company operations continue normally - this is a personnel matter.\n4. We have strong governance structures in place.\n5. We will share findings as appropriate while respecting the investigative process.', 'Investors, Analysts', 'Professional, Authoritative', 'Robert Johnson', false, 'approved'),
(5, 'Warehouse Fire - Operations Update', '1. All employees were safely evacuated - no injuries.\n2. Fire department responded quickly and fire is fully contained.\n3. We have insurance coverage and are filing claims.\n4. Customer orders will be fulfilled from alternative warehouses.\n5. Cause is under investigation but preliminary signs do not suggest foul play.', 'Customers, Partners', 'Calm, Solution-focused', 'Sarah Chen', false, 'used'),
(6, 'Viral Video - Social Media Response', '1. We take every customer concern seriously regardless of how it comes to our attention.\n2. We have reached out directly to the customer in the video.\n3. Our quality team is investigating the specific incident.\n4. This does not reflect the experience of our millions of satisfied customers.\n5. We encourage anyone with product concerns to contact us directly.', 'Social Media Users', 'Empathetic, Responsive', 'Emily Taylor', true, 'approved'),
(7, 'Labor Strike - Company Position', '1. We respect our employees rights and value their contributions.\n2. We have been negotiating in good faith for six months.\n3. Our proposal includes meaningful wage increases and enhanced benefits.\n4. We remain at the table and committed to reaching an agreement.\n5. We will not discuss specific negotiation details publicly.', 'Media, Public', 'Respectful, Firm', 'Michael Lee', false, 'approved'),
(9, 'FDA Investigation - Regulatory Response', '1. We welcome the opportunity to demonstrate our compliance.\n2. Patient safety is and has always been our paramount concern.\n3. We are fully cooperating with the FDA.\n4. Our products continue to meet all safety and efficacy standards.\n5. We maintain rigorous compliance programs that go beyond minimum requirements.', 'Regulators, Healthcare Providers', 'Cooperative, Confident', 'Daniel Kim', false, 'approved'),
(10, 'Workplace Safety - OSHA Response', '1. We deeply regret this incident and our thoughts are with the affected employee.\n2. The employee is receiving full medical care and is expected to recover.\n3. We immediately halted operations for a comprehensive safety review.\n4. We have reported to OSHA and are fully cooperating.\n5. Additional safety measures have been implemented to prevent recurrence.', 'OSHA, Employees, Media', 'Concerned, Responsible', 'Amanda White', false, 'used'),
(11, 'Misinformation - Factual Response', '1. The claims being spread online about our products are categorically false.\n2. Our products meet or exceed all regulatory requirements.\n3. We have commissioned independent laboratory testing - results will be public.\n4. We are working with platforms to address the coordinated spread of false information.\n5. Consumers can verify our product information at [website].', 'Public, Media', 'Firm, Factual', 'Rachel Davis', true, 'approved'),
(12, 'Hurricane Response - Employee Safety', '1. Employee safety is our first and only priority right now.\n2. All non-essential operations suspended at Gulf Coast facilities.\n3. Employees should follow local authority evacuation orders.\n4. Emergency financial assistance available for affected employees.\n5. Do not return to facilities until official all-clear is issued.', 'Employees', 'Urgent, Caring', 'Chris Anderson', false, 'approved'),
(1, 'Chemical Spill - Environmental Impact', '1. Containment has been successful - the spill has not reached any waterways.\n2. Environmental monitoring is ongoing with results shared publicly.\n3. We have engaged environmental remediation experts.\n4. Full cleanup and restoration is our commitment.\n5. We will fund independent environmental assessment by a community-chosen firm.', 'Environmental Groups, Regulators', 'Responsible, Proactive', 'Sarah Chen', true, 'draft'),
(4, 'Executive Investigation - Employee Communication', '1. I want to address the news reports directly - you deserve to hear from leadership first.\n2. The Board has taken appropriate action and an investigation is underway.\n3. This does not change your jobs, your teams, or our mission.\n4. Please direct any media inquiries to our PR team.\n5. We will share what we can as the process unfolds. Your focus should remain on serving our customers.', 'Employees', 'Supportive, Direct', 'CEO', false, 'approved'),
(14, 'Data Privacy Lawsuit - Public Position', '1. We believe the allegations are without merit.\n2. We maintain robust data privacy practices.\n3. We comply with all applicable data protection regulations.\n4. We will vigorously defend our position through proper legal channels.\n5. We remain committed to transparency in our data practices.', 'Public, Media', 'Confident, Measured', 'Thomas Martinez', false, 'approved')
INSERT INTO post_crisis_analyses (crisis_id, title, summary, what_went_well, what_went_wrong, recommendations, metrics, ai_analysis, status) VALUES
(10, 'Workplace Safety Incident Analysis - Chicago Plant A', 'Analysis of the manufacturing line accident that resulted in one employee injury. The incident occurred during a routine maintenance operation when a safety guard was temporarily removed.', 'Emergency response was swift - medical team on site in 3 minutes. OSHA notification completed within required timeframe. Employee received immediate medical attention. Communication to workforce was transparent and timely.', 'Safety guard lockout/tagout procedure was not followed. Pre-shift safety checklist was incomplete. Supervisor oversight during maintenance was insufficient. Near-miss reporting system had flagged similar risks 2 months prior without corrective action.', '1. Implement mandatory buddy system for all maintenance operations.\n2. Install electronic lockout/tagout verification system.\n3. Require supervisor sign-off on all pre-shift safety checklists.\n4. Create escalation protocol for near-miss reports.\n5. Conduct quarterly safety culture assessments.', 'Response time: 3 minutes. OSHA notification: Within 8 hours. Employee recovery: Expected full recovery in 6 weeks. Days since previous incident before this: 247. Safety training hours per employee: 24/year.', 'Root cause analysis reveals systemic gap between safety policy and practice. The near-miss reporting data from 2 months prior should have triggered preventive action. This represents a process failure rather than individual failure. Recommend focusing corrective actions on systemic improvements rather than individual accountability.', 'final'),
(1, 'Chemical Spill Response - Preliminary Analysis', 'Preliminary analysis of the Plant B chemical spill response. Full analysis pending completion of environmental remediation.', 'Emergency response team activated within 8 minutes. Containment prevented spread to waterways. EPA notification completed within regulatory timeframe. Press conference held within 4 hours of incident. No injuries reported.', 'Tank monitoring systems did not provide adequate advance warning. Emergency response equipment staging was suboptimal - 10 minute delay in barrier deployment. Initial community notification was delayed by 45 minutes. Internal communication chain had gaps.', '1. Upgrade tank monitoring to real-time pressure and integrity sensors.\n2. Pre-position emergency response equipment closer to high-risk areas.\n3. Implement automated community notification system.\n4. Create dedicated crisis communication channel for internal coordination.\n5. Conduct quarterly emergency drills at all chemical storage facilities.', 'Detection to response: 8 minutes. Containment completion: 45 minutes. EPA notification: 25 minutes. Media response: 4 hours. Community notification: 1 hour 45 minutes. Estimated remediation cost: $500K-$1M.', 'Response was generally effective but several timing gaps identified. The 45-minute community notification delay is the most significant finding - regulatory best practice is 30 minutes. Tank infrastructure age (25+ years) is the fundamental risk factor requiring capital investment.', 'draft'),
(2, 'Data Breach Response Assessment - In Progress', 'Assessment of the cybersecurity incident response and communication strategy. Investigation still ongoing.', 'Detection through internal monitoring rather than external discovery. Swift credential revocation (45 minutes from detection). Customer notification exceeded regulatory requirements. Credit monitoring offer well-received by customers.', 'Vendor credential management was inadequate. Database access controls were too permissive. Initial scope assessment underestimated affected records. Crisis hotline was understaffed for call volume.', '1. Implement privileged access management (PAM) for all vendor accounts.\n2. Apply principle of least privilege to all database access.\n3. Increase crisis hotline surge capacity.\n4. Conduct monthly vendor security audits.\n5. Implement data loss prevention (DLP) tools.', 'Detection to containment: 45 minutes. Records affected: 50,000. Customer notification: Within 24 hours. Hotline calls handled: 847 in first 6 hours. Average wait time: 4 minutes. Credit monitoring enrollment: 62% of affected customers.', 'The breach vector (compromised vendor credentials) is the #1 attack vector in 2026. The company detection time of 45 minutes is significantly better than industry average of 197 days. However, the permissive database access controls amplified the impact. Recommend zero-trust architecture implementation.', 'draft'),
(3, 'Product Recall X500 - Preliminary Review', 'Review of the voluntary recall process for Model X500 battery defect. Recall still in progress.', 'Defect identified through internal testing before any customer injuries. Voluntary recall decision made within 48 hours of discovery. Clear and simple return process for customers. Retail partner coordination was efficient.', 'Quality testing interval may have been too long - defect could have been caught earlier. Initial production quality controls did not detect the issue. Customer communication could have been more personalized. Website crashed under traffic load during announcement.', '1. Increase frequency of post-production quality testing.\n2. Add battery stress testing to production line QC.\n3. Scale web infrastructure for crisis traffic.\n4. Develop personalized customer communication templates.\n5. Create dedicated recall management team.', 'Units affected: 25,000. Return rate: 45% (ongoing). Customer complaints pre-recall: 0. Time from discovery to recall announcement: 48 hours. CPSC notification: Within 24 hours. Estimated total cost: $15-20M.', 'The proactive voluntary recall is a textbook best practice and will likely reduce litigation risk significantly. The 48-hour decision timeline is commendable. Website infrastructure failure during announcement is a recurring issue across industries - recommend CDN and load balancing for crisis pages.', 'draft'),
(5, 'Warehouse Fire - Insurance and Recovery Analysis', 'Analysis of the Newark warehouse fire response, insurance claims process, and supply chain recovery.', 'Zero injuries due to effective evacuation. Fire department response coordination was excellent. Insurance claim filed promptly. Alternative fulfillment arrangements implemented within 24 hours.', 'Fire suppression system in Warehouse 7 was due for maintenance. Inventory was not adequately distributed across multiple locations. Backup fulfillment capacity was barely sufficient.', '1. Implement strict fire suppression system maintenance schedule.\n2. Distribute inventory across minimum 3 warehouse locations.\n3. Build 20% excess fulfillment capacity across network.\n4. Install advanced fire detection systems.\n5. Review and update business continuity plans annually.', 'Evacuation time: 4 minutes. Fire department response: 7 minutes. Inventory loss: $2M. Insurance claim filed: Same day. Alternative fulfillment active: 24 hours. Customer order delays: Average 2 days.', 'Fire suppression maintenance gap is the critical finding. Industry data shows facilities with overdue maintenance have 5x higher loss severity. The rapid alternative fulfillment activation demonstrates good business continuity planning. Recommend geographic diversification of inventory.', 'draft'),
(6, 'Viral Social Media Incident - Digital Response Review', 'Review of social media crisis response to viral product complaint video.', 'Rapid detection of viral content (within 1 hour of significant spread). Direct outreach to affected customer was well-received. Social media response team maintained professional tone throughout. Negative trend stabilized within 48 hours.', 'Initial response template felt generic. Did not have pre-approved content for this scenario type. Competitor brands capitalized on the situation with comparative messaging. Internal approval chain slowed response by 2 hours.', '1. Develop pre-approved response templates for common viral scenarios.\n2. Reduce social media crisis approval chain to 2 levels.\n3. Monitor competitor activity during social media crises.\n4. Train customer service team on social media escalation.\n5. Build library of authentic customer success stories for counter-narrative.', 'Time to detection: 1 hour. Time to first response: 3 hours. Peak negative mentions: 15,000/hour. Sentiment recovery time: 48 hours. Video views: 2.1M. Follow-up positive engagement: 45% increase after customer resolution.', 'The 3-hour response time is at the upper limit of acceptable for social media crises. The customer resolution story became a positive narrative - this pattern should be replicated. Recommend investing in AI-powered social listening tools for faster detection.', 'final'),
(7, 'Labor Strike Negotiation - Communication Analysis', 'Analysis of communication strategy during labor dispute and strike negotiations.', 'Maintained respectful tone throughout public communications. Did not engage in public blame game. Negotiation team was well-prepared. Employee communication was consistent and timely.', 'Public statement timing was reactive rather than proactive. Social media discussion was largely dominated by union messaging. Did not adequately communicate company proposal benefits to broader public. Internal communication to non-union employees was insufficient.', '1. Develop proactive communication timeline for labor disputes.\n2. Create social media content strategy for labor negotiations.\n3. Prepare public-friendly summaries of company proposals.\n4. Include non-union employee communication in crisis plan.\n5. Engage community stakeholders as neutral third parties.', 'Duration of negotiations: 6 months. Strike notice: 7 days. Company proposals presented: 3. Media mentions: 450+. Social media sentiment: 60% pro-union, 25% neutral, 15% pro-company. Employee communications sent: 12.', 'Communication was appropriate but not strategic enough. The 60/25/15 sentiment split suggests the company narrative was not effectively reaching the public. In future labor disputes, recommend earlier proactive communication to establish the company as a fair employer.', 'draft'),
(9, 'FDA Investigation Communication Strategy Review', 'Review of communication approach during FDA preliminary inquiry into pharmaceutical division.', 'Immediate cooperation stance with FDA. Proactive document submission. Healthcare provider communication was professional and reassuring. Did not create unnecessary public alarm.', 'Initial internal communication created some employee anxiety. Media statement was perceived as too defensive by some analysts. Did not adequately prepare for leaked investigation details. Investor communication was delayed.', '1. Develop regulatory investigation playbook with pre-drafted communications.\n2. Train employees on regulatory investigation protocols annually.\n3. Prepare tiered media statements from acknowledgment to resolution.\n4. Establish rapid investor communication protocol for regulatory events.\n5. Engage former regulatory officials as advisors proactively.', 'FDA notification to public awareness: 3 days (leaked). Investor communication delay: 48 hours. Media inquiries: 75+. Healthcare provider inquiries: 120. Stock impact: -3.5% on news. Employee questions to HR: 200+.', 'The 48-hour investor communication delay is the most significant gap. In regulated industries, investor expectations for rapid disclosure are higher. The cooperation stance with FDA was strategically correct and should reduce investigation duration by an estimated 30%.', 'draft'),
(11, 'Misinformation Campaign Response Analysis', 'Analysis of response to coordinated disinformation campaign targeting product ingredients.', 'Quick identification of bot network involvement. Effective coordination with social media platform trust teams. Independent lab testing was a strong credibility move. Brand advocates emerged organically.', 'Took 24 hours to publish definitive fact-check content. Did not anticipate cross-platform spread. Initial response focused too much on denial rather than proactive proof. Legal review slowed content approval.', '1. Pre-prepare fact-check content library for common false claims.\n2. Develop cross-platform monitoring and response capability.\n3. Lead with proof rather than denial in misinformation responses.\n4. Create expedited legal review process for crisis content.\n5. Build and maintain a brand advocate network for rapid amplification.', 'Bot accounts identified: 2,300. False claim impressions: 12M. Platform removals: 1,800 accounts. Fact-check engagement: 500K. Time to trend reversal: 72 hours. Independent lab results published: Day 3.', 'Misinformation campaigns are becoming more sophisticated. The 72-hour trend reversal is acceptable but could be improved to 48 hours with pre-prepared content. The commercial nature of the bot network suggests this was a paid attack - recommend investigation into potential competitors or adversaries.', 'final'),
(12, 'Hurricane Preparedness Execution Review', 'Review of hurricane emergency response plan execution for Gulf Coast facilities.', 'All employees accounted for within 3 hours. Evacuation plans executed smoothly. Business continuity plans activated on schedule. Employee emergency assistance program received positive feedback.', 'Two remote locations had communication gaps during evacuation. Some employees did not receive SMS alerts due to outdated contact information. Pre-positioned supplies at one location were insufficient. Post-storm facility access assessment was delayed.', '1. Install satellite communication backup at all facilities.\n2. Conduct quarterly employee contact information verification.\n3. Increase pre-positioned emergency supply levels by 50%.\n4. Develop drone-based facility assessment capability for post-storm evaluation.\n5. Create mutual aid agreements with facilities in non-affected regions.', 'Employees evacuated: 5,200. Facilities secured: 3. Communication gaps: 2 locations. Employee assistance applications: 340. Business continuity activation time: 4 hours. Estimated property protection savings: $3M.', 'Emergency preparedness plan was 85% effective. The 15% gap is primarily communication infrastructure related. Satellite communication backup is the highest priority improvement. Employee contact database currency of 85% needs to reach 98% minimum for effective emergency notification.', 'draft'),
(13, 'Merger Leak - Information Security Review', 'Analysis of information security breach that led to premature disclosure of acquisition discussions.', 'Legal team responded rapidly to assess SEC implications. Holding statement was appropriate and did not confirm or deny. Market communication maintained regulatory compliance.', 'Information barrier procedures were insufficient. Leak source not immediately identified. Some employees discussed the reports on social media. SEC proactive engagement was delayed by 24 hours.', '1. Strengthen information barrier procedures with digital access controls.\n2. Implement deal-specific communication protocols.\n3. Train employees on MNPI handling annually.\n4. Establish immediate SEC notification protocol for potential leaks.\n5. Review and restrict access to deal information to essential personnel only.', 'Time from leak to market awareness: 4 hours. Stock price movement: +12%. SEC notification: 48 hours post-leak. Personnel with deal access: 23. Social media employee posts: 7. Media inquiries: 95.', 'The leak represents a significant compliance failure. The 23 people with deal access is higher than best practice (typically 10-15 for deals of this size). Employee social media activity during the event suggests inadequate MNPI training. SEC engagement delay increases regulatory risk.', 'draft'),
(14, 'Data Privacy Lawsuit - Communication Strategy Assessment', 'Assessment of communication approach for class action data privacy litigation.', 'Legal communication was measured and appropriate. Did not make any admissions in public statements. Customer communication maintained confidence in data practices.', 'Reactive rather than proactive public positioning. Did not effectively communicate existing privacy protections. Some customer inquiries went unanswered for 48+ hours. Privacy policy page on website was not updated to address concerns.', '1. Develop proactive privacy communication campaign.\n2. Create dedicated privacy FAQ page on website.\n3. Ensure customer inquiry response within 4 hours during crisis.\n4. Publish annual transparency report on data practices.\n5. Consider appointing customer-facing Chief Privacy Officer.', 'Customer inquiries: 1,200. Average response time: 36 hours. Media mentions: 180. Customer churn attributed to incident: 2.3%. Social media sentiment: 70% negative. Privacy page visits: 45,000 (10x normal).', 'The 2.3% customer churn is lower than average for data privacy incidents (typically 3-5%), suggesting the overall approach was effective despite gaps. The 36-hour average response time needs significant improvement. Proactive privacy communication would have reduced inquiry volume by an estimated 40%.', 'draft'),
(15, 'Environmental Protest - Community Engagement Review', 'Review of community engagement approach during environmental activist protests.', 'Did not escalate confrontation. Community forum invitation was well-received. Maintained open dialogue throughout. Security handled protester interactions professionally.', 'Initial response was slow (12 hours to first public statement). Did not engage environmental group leadership early enough. Internal talking points were not aligned across departments. Media coverage was largely sympathetic to protesters.', '1. Develop environmental stakeholder engagement program.\n2. Create rapid response protocol for activist events.\n3. Align all departmental talking points through central crisis team.\n4. Establish ongoing dialogue with environmental advocacy groups.\n5. Invest in visible environmental sustainability initiatives.', 'Protester count: Peak 200. Duration: 3 days. Media stories: 25. Community forum attendance: 150. Social media sentiment shift post-forum: 20% improvement. Employee volunteer sign-ups for community cleanup: 75.', 'The community forum was the turning point - 20% sentiment improvement demonstrates the power of face-to-face engagement. The 12-hour initial response delay allowed the narrative to be established by protesters. Environmental sustainability investments would provide ongoing reputation protection.', 'final'),
(1, 'Chemical Spill - 72-Hour Review', 'Comprehensive 72-hour review of the chemical spill response at Plant B facility.', 'Containment was effective - no environmental spread beyond initial perimeter. Multi-agency coordination (EPA, local fire, hazmat) worked well. Public communication cadence was appropriate (4 updates in 72 hours). Community town hall was well-attended and productive.', 'Initial spill volume was underestimated by 30%. Environmental monitoring data sharing with community was not real-time. Clean-up contractor mobilization took 18 hours vs. target of 12 hours. Employee communication to off-shift workers was delayed.', '1. Improve spill estimation protocols and training.\n2. Implement real-time environmental data dashboard accessible to community.\n3. Pre-contract emergency cleanup services with guaranteed response times.\n4. Create off-shift employee emergency notification system.\n5. Establish community environmental advisory panel.', 'Containment time: 45 minutes. Area affected: 0.5 acres. Cleanup progress at 72 hours: 60%. Community complaints: 34. EPA violations cited: 0. Air quality readings: Within limits. Water quality: No contamination detected.', 'The zero EPA violations is the most significant positive outcome. The spill volume underestimation (30%) could have had serious consequences if actual volume had been larger. Real-time community data sharing would significantly improve trust and reduce complaint volume. Overall response grade: B+.', 'draft')
